public enum OrderStatus
{
    /// <summary>
    /// The order has been created but not yet processed.
    /// </summary>
    Created,

    /// <summary>
    /// The order is being processed and may be updated.
    /// </summary>
    Processing,

    /// <summary>
    /// The order has been completed and is ready for shipment.
    /// </summary>
    Completed,

    /// <summary>
    /// The order has been cancelled and is no longer valid.
    /// </summary>
    Cancelled
}

public static class OrderStatusExtensions
{
    public static bool IsProcessing(this OrderStatus status)
    {
        return status == OrderStatus.Processing;
    }

    public static bool IsCompleted(this OrderStatus status)
    {
        return status == OrderStatus.Completed;
    }

    public static bool IsCancelled(this OrderStatus status)
    {
        return status == OrderStatus.Cancelled;
    }
}

